use std::collections::HashMap;

struct ServerConfig {
    ip_address: String,
    port: u16,
}

fn main() {
    let mut servers: HashMap<String, Option<ServerConfig>> = HashMap::new();
    servers.insert("A".to_string(), Some(ServerConfig { ip_address: "10.0.0.1".to_string(), port: 80 }));
    servers.insert("B".to_string(), None);
    servers.insert("C".to_string(), Some(ServerConfig { ip_address: "10.0.0.2".to_string(), port: 443 }));

    let mut active_servers = Vec::new();

    for (name, config_opt) in servers {
        if let Some(config) = config_opt {
            active_servers.push((name, config));
        }
    }

    println!("Found {} active server configurations.", active_servers.len());

    for (name, config) in active_servers {
        println!("Processing server {}: IP {} on port {}", name, config.ip_address, config.port);
    }
}

use std::collections::HashMap;
use std::time::{Duration, Instant};

struct JobStatus {
    status: String,
    payload_id: u32,
}

fn process_webhook_dispatch(jobs: Vec<JobStatus>) -> HashMap<u32, String> {
    let mut results = HashMap::new();
    for job in jobs {
        match job.status.as_str() {
            "success" => {
                results.insert(job.payload_id, format!("Successfully processed."));
            }
            "pending" => {
                println!("Job {} is pending; scheduling retry later.", job.payload_id);
                // In a real system, this would enqueue a background job or timer
                results.insert(job.payload_id, String::from("Pending for retry"));
            }
            "failed_temp" => {
                let backoff = Duration::from_secs(5);
                println!("Job {} failed temporarily; waiting for {:?}.", job.payload_id, backoff);
                std::thread::sleep(backoff);
                results.insert(job.payload_id, String::from("Failed, scheduled retry with backoff"));
            }
            s => {
                println!("Job {} has unknown status: {}. Logging for manual review.", job.payload_id, s);
                results.insert(job.payload_id, format!("Manual check required due to unexpected status: {}", s));
            }
        }
    }
    results
}

use std::collections::HashMap;

struct Server {
    id: u64,
    is_online: bool,
}

impl From<HashMap<u64, String>> for Server {
    fn from(_map: HashMap<u64, String>) -> Self {
        Server { id: 0, is_online: true }
    }
}

fn find_available_server<'a>(servers: &'a [&'a Server], key: u64) -> Option<&'a Server> {
    for server in servers.iter() {
        if server.id == key {
            if server.is_online {
                return Some(server);
            }
        }

        let next_key = (key + 1) % 3;
        if let Some(next_server) = servers.iter().find(|s| s.id == next_key) {
            if next_server.is_online && next_server.id != key {
                return Some(next_server);
            }
        }
    }
    None
}

fn main() {
    let mut server_map: HashMap<u64, String> = HashMap::new();
    server_map.insert(100, "ServerA".to_string());
    server_map.insert(200, "ServerB".to_string());
    server_map.insert(300, "ServerC".to_string());

    let servers = vec![&Server { id: 100, is_online: true }, &Server { id: 200, is_online: false }, &Server { id: 300, is_online: true }];

    let user_key = 200;

    match find_available_server(&servers, user_key) {
        Some(server) => println!("Successfully connected to server ID: {}", server.id),
        None => println!("All servers appear to be offline or unavailable.")
    }
}

use std::fs::File;
use std::io::{self, Read};

struct ScanResult {
    success: bool,
    message: String,
}

fn attempt_read(path: &str) -> Result<Vec<u8>, io::Error> {
    let mut file = File::open(path)?;
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?;
    Ok(buffer)
}

fn scan_file(data: &[u8]) -> Result<ScanResult, String> {
    if data.len() < 10 { 
        return Err("File too small for proper scanning".to_string());
    }
    if data[0] == 0xFF && data[1] == 0xDB { 
        Ok(ScanResult { success: false, message: "Detected potential ZIP header pattern".to_string() })
    } else {
        Ok(ScanResult { success: true, message: "Virus scan complete. Clean.".to_string() })
    }
}

fn process_upload(path: &str) -> Result<String, String> {
    let data = match attempt_read(path) {
        Ok(bytes) => bytes,
        Err(e) => return Err(format!("Failed to open file: {}", e)),
    };

    match scan_file(&data) {
        Ok(result) => {
            if result.success {
                Ok(format!("Successfully processed and scanned '{}'. Result: {}", path, result.message))
            } else {
                Err(format!("Scanning failed for '{}'. Reason: {}", path, result.message))
            }
        },
        Err(e) => Err(format!("Error during scan phase for '{}': {}", path, e)),
    }
}

fn main() {
    let test_path = "test_upload.bin";
    println!("Attempting to process file: {}", test_path);
    match process_upload(test_path) {
        Ok(msg) => println!("SUCCESS: {}", msg),
        Err(e) => println!("FAILURE: {}", e)
    }
}

use std::collections::HashMap;

struct Shape {
    kind: String,
    data: Option<i32>,
}

impl Shape {
    fn new(kind: &str, data: Option<i32>) -> Self {
        Shape { kind: kind.to_string(), data: data }
    }
}

struct TileEngine {
    entity_map: HashMap<u32, Shape>,
}

impl TileEngine {
    fn new() -> Self {
        TileEngine { entity_map: HashMap::new() }
    }

    fn add_shape(&mut self, id: u32, shape: Shape) {
        self.entity_map.insert(id, shape);
    }

    fn process_tile_interactions(&self) {
        for (entity_id, shape) in &self.entity_map {
            match shape {
                Shape { kind: s_kind, data: Some(val) } if s_kind == "Square" => {
                    println!("Entity {} found a Square with value {}", entity_id, val);
                }
                Shape { kind: s_kind, data: None } if s_kind.contains("Circle") => {
                    println!("Entity {} found an empty Circle", entity_id);
                }
                Shape { kind: s_kind, data: Some(val) } => {
                    println!("Entity {} processed a generic shape '{}' with value {}", entity_id, s_kind, val);
                }
                _ => {
                    println!("Entity {} ignored unhandled shape", entity_id);
                }
            }
        }
    }
}

fn main() {
    let mut engine = TileEngine::new();
    engine.add_shape(101, Shape::new("Square", Some(42)));
    engine.add_shape(102, Shape::new("Circle Outline", None));
    engine.add_shape(103, Shape::new("Triangle Solid", Some(7)));
    engine.add_shape(104, Shape::new("UnknownBlob", None));

    engine.process_tile_interactions();
}
